    tmp18 = einsum(r2.bbb, (0, 1, 2), t2.bbbb, (3, 4, 0, 1), (2, 3, 4))
    r2new.bbb += einsum(tmp18, (0, 1, 2), v.bbbb.ovov, (2, 3, 1, 4), (3, 4, 0)) * -1
    del tmp18
    r2new.bbb += np.transpose(tmp17, (2, 1, 0)) * -2
    del tmp17

    return {"r1new": r1new, "r2new": r2new}

